import { Component, OnInit } from '@angular/core';
import { Register } from '../interfaces/register';
import { RegistrosService } from '../services/registrosService';
import Swal from 'sweetalert2';

@Component({
  selector: 'app-registros-por-categoria',
  templateUrl: './registros-por-categoria.component.html',
  styleUrls: ['./registros-por-categoria.component.css'],
})
export class ListRegistrosComponent implements OnInit {
  listaRegistros: Register[] = [];

  constructor(private registrosService: RegistrosService) {}

  ngOnInit() {
    this.registrosService.getRegistrosPorCategoria("supermercado").subscribe(
      (registros) => {
        this.listaRegistros = registros;
        console.log(this.listaRegistros);
      },
      (error) => {
        console.error('Error al cargar los registros:', error);
      }
    );
  }

}
